#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d",&N,&M);
        char A[100005]; scanf("%s",A);
        long long onesA=0; for(int i=0;i<N;i++) if(A[i]=='1') onesA++;
        long long totalOnes = onesA * (long long)M;
        if(onesA==0){
            printf("%lld\n", (long long)N * M);
            continue;
        }
        if(totalOnes % 2){
            printf("0\n");
            continue;
        }
        long long target = totalOnes/2;
        long long pref=0; long long ans=0;
        for(int i=0;i<N;i++){
            if(A[i]=='1') pref++;
            long long diff = target - pref;
            if(diff>=0 && diff % onesA == 0){
                long long c = diff / onesA;
                if(c >= 0 && c < M) ans++;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

