import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            String A = fs.next();
            long onesA = 0;
            for (int i = 0; i < N; i++) if (A.charAt(i) == '1') onesA++;
            long totalOnes = onesA * M;
            if (onesA == 0) {
                sb.append((long)N * M).append('\n');
                continue;
            }
            if ((totalOnes & 1L) == 1L) {
                sb.append(0).append('\n');
                continue;
            }
            long target = totalOnes / 2;
            long pref = 0, ans = 0;
            for (int i = 0; i < N; i++) {
                if (A.charAt(i) == '1') pref++;
                long diff = target - pref;
                if (diff >= 0 && diff % onesA == 0) {
                    long c = diff / onesA;
                    if (c >= 0 && c < M) ans++;
                }
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException { int c, sign = 1, val = 0; do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + c - '0'; c = readByte(); }
            return val * sign; }
        String next() throws IOException { int c; do { c = readByte(); } while (c <= ' ');
            StringBuilder sb = new StringBuilder();
            while (c > ' ') { sb.append((char)c); c = readByte(); }
            return sb.toString(); }
    }
}

